import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'


export const orderSlice = createSlice({
    name: 'order',
    initialState: {},
    reducers: {
        orderCreateRequest: (state) => { 
            state.loading = true;
        },
        orderCreateSuccess: (state, action) => { 
            state.loading = false;
            state.success = true;
            state.order = action.payload; 
        },
        orderCreateFail: (state, action) => { 
            state.loading = false; 
            state.error = action.payload;
        },
    }
})
export const { orderCreateRequest, orderCreateSuccess, orderCreateFail } = orderSlice.actions
export default orderSlice.reducer;


// thunk function to fetch the product details
export const addOrder = (data) => async (dispatch) => {
    try{
        dispatch(orderCreateRequest());
        const { data } = await axios.post('/api/orders/add/');
        dispatch(orderCreateSuccess(data));

    } catch (error) {
        const msg = (error.response && error.response.data.detail ? error.response.data.detail : error.message)
        dispatch(orderCreateFail(msg))
    }
}
